const express = require('express');
const AdvertisementController = require('../controllers/advertisementController');
const { authenticateToken } = require('../middleware/auth');

const router = express.Router();

// 所有路由都需要认证
router.use(authenticateToken);

// 创建广告投放
router.post('/', AdvertisementController.createAdvertisement);

// 获取用户广告列表
router.get('/user', AdvertisementController.getUserAdvertisements);

// 获取活跃广告列表
router.get('/active', AdvertisementController.getActiveAdvertisements);

// 获取广告详情
router.get('/:adId', AdvertisementController.getAdvertisementDetails);

// 记录广告浏览
router.post('/:adId/view', AdvertisementController.recordAdvertisementView);

// 删除广告
router.delete('/:adId', AdvertisementController.deleteAdvertisement);

// 管理员：审核广告
router.put('/:adId/review', AdvertisementController.reviewAdvertisement);

module.exports = router;
